scriptContent:
# Chokepoint Remote Execution Emulation
# IPC$ connection, random service creation, cmd recon
# Expected Detections: WEL 4624 (LogonType 3), 7045 (service install), EID 1 (cmd.exe)

[CmdletBinding()]
param(
    [string]$TargetHost = "127.0.0.1",
    [switch]$DryRun
)

Write-Host "=== Chokepoint Remote Execution Emulation ===" -ForegroundColor Cyan
Write-Host "Emulating lateral movement via remote service creation"

# Stage 1: IPC$ connection (WEL 4624 target)
Write-Host "\n[Stage 1] Establishing IPC$ connection..."
if (-not $DryRun) {
    try {
        $ipcPath = "\\$TargetHost\IPC$"
        Write-Host "  Target: $ipcPath" -ForegroundColor Yellow
        # Attempt IPC$ connection (may fail on localhost, but generates log)
        net use $ipcPath /user:localhost dummy 2>$null | Out-Null
        Write-Host "  Action: IPC$ connection attempted" -ForegroundColor Yellow
        Write-Host "  Expected Detection: WEL 4624 (LogonType 3 - Network)" -ForegroundColor Cyan
    } catch {
        Write-Host "  IPC$ connection failed (expected for emulation)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would attempt IPC$ connection to $TargetHost" -ForegroundColor Magenta
}

# Stage 2: Random service creation (WEL 7045 target)
Write-Host "\n[Stage 2] Creating random service..."
$randomSvcName = "Svc" + (Get-Random -Minimum 1000 -Maximum 9999)

if (-not $DryRun) {
    try {
        sc.exe create $randomSvcName binPath= "cmd.exe /c echo test" start= auto
        Write-Host "  Created service: $randomSvcName" -ForegroundColor Yellow
        Write-Host "  Expected Detection: WEL 7045 (ServiceInstall)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error creating service: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would create service: $randomSvcName" -ForegroundColor Magenta
}

# Stage 3: Command reconnaissance (EID 1 target)
Write-Host "\n[Stage 3] Executing reconnaissance commands..."
if (-not $DryRun) {
    try {
        $reconCommands = "whoami /all & hostname & ipconfig /all & net user & net localgroup administrators"
        Start-Process cmd.exe -ArgumentList "/c", $reconCommands -Wait -NoNewWindow
        Write-Host "  Action: Recon commands executed via cmd.exe" -ForegroundColor Yellow
        Write-Host "  Expected Detection: EID 1 (ProcessCreate - cmd.exe with recon)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would execute recon commands" -ForegroundColor Magenta
}

# Stage 4: Cleanup service
Write-Host "\n[Stage 4] Cleaning up service..."
if (-not $DryRun -and $randomSvcName) {
    try {
        sc.exe delete $randomSvcName 2>$null | Out-Null
        Write-Host "  Deleted service: $randomSvcName" -ForegroundColor Yellow
    } catch {
        Write-Host "  Error deleting service" -ForegroundColor Red
    }
}

Write-Host "\n=== Emulation Complete ===" -ForegroundColor Cyan
Write-Host "Expected Detections:"
Write-Host "  - WEL 4624: Network logon (LogonType 3)" -ForegroundColor Green
Write-Host "  - WEL 7045: Service installation" -ForegroundColor Green
Write-Host "  - EID 1: cmd.exe with reconnaissance commands" -ForegroundColor Green
